external_knowledge:
- 'Bottom' depth refers to the deepest point measured for the sample;
- 'Average temperature' is calculated from multiple measurements;
- 'Average rainfall' is calculated from multiple surveys;
- 'Files' are documents or data files associated with the sample;
- 'Chemical concentrations' are the total amounts of specific chemicals measured in the sample.

sql:
WITH FirstMeasurementTime AS (
    SELECT sample_id, MIN(measurement_time) AS first_measurement_time
    FROM sample_measurements
    GROUP BY sample_id
)
SELECT AVG(
    (
        STRFTIME('%s', T2.first_measurement_time) - STRFTIME('%s', T1.sample_time)
    ) / 60.0
) AS avg_time_diff_minutes
FROM samples T1
INNER JOIN FirstMeasurementTime T2 ON T1.sample_id = T2.sample_id;

